    },
    {
      "parameters": {
        "jsCode": "// Genera un item por página a paginar.\n// Usa total_a_procesar: puede ser delta o total Mailjet si hay nuevos contactos.\n// Propaga ts_efectivo como last_sync_unix para el filtro de HTTP GET Contacts Page.\nconst total = Number($json.total_a_procesar ?? 0);\nconst limit = 1000;\nconst pages = Math.max(1, Math.ceil(total / limit));\nconst ts_efectivo = $('Code Decidir ts_efectivo').first().json.ts_efectivo;\nreturn Array.from({ length: pages }, (_, i) => ({\n  json: { offset: i * limit, pageLimit: limit, last_sync_unix: ts_efectivo }\n}));"
      },
